export function lookupByAlias(key: string): AnnArborNpnSpeciesEntry | undefined {
  const acronym = ALIAS_INDEX.get(key.toLowerCase());
  if (!acronym) return undefined;
  return ANN_ARBOR_NPN_DATA.find((s) => s.acronym === acronym);
}